## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "parserAssignment.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
($X, $Y) = random_subset(2, 'a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context("Fraction")->variables->are($X => 'Real', $Y => 'Real');
Context()->noreduce('(-x)-y', '(-x)+y');
parser::Assignment->Allow;
$A[0] = Fraction(random_coprime([1..5],[2..6]));
$B[0] = Fraction(random_coprime([-5..-1,1..5],[2..6]));
$A[1] = Fraction(random_coprime([1..5],[2..6]));
$B[1] = $B[0]*$A[1]/$A[0];
do {
  @C = map{Fraction(random_coprime([-5..-1,1..5],[2..6]))} (0,1)
} until ($C[1] != $C[0]*$A[1]/$A[0]);
Context()->strings->remove("NONE");
Context()->strings->add(
  "no solutions" => {},
);
for (
  "no solution",
  "none",
  "there are no solutions",
  "the solution set is empty",
  "solution set is empty",
  "empty set",
  "∅",
  "{}",
  "{ }",
  "{  }",
  "{   }"
) {
  Context()->strings->add($_ => {alias => "no solutions"});
}
Context()->strings->add(
  "infinitely many solutions" => {},
);
for (
  "infinitely many",
  "infinite solution set",
  "infinite",
  "the solution set is infinite",
  "solution set is infinite"
) {
  Context()->strings->add($_ => {alias => "infinitely many solutions"});
}
$solution = Compute("no solutions");
$answer = $solution->cmp(
  typeMatch => List("$X = 0, $Y = 0"),
  mathQuillOpts => 'disabled'
);
@left = map{Formula("$A[$_] $X + $B[$_] $Y")->reduce} (0,1);
@right = map{Formula("$C[$_]")->reduce} (0,1);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the system of equations using substitution.

[`\newcommand{\amp}{&}\left\{
                  \begin{alignedat}{4}
                  \amp [$left[0]] = [$right[0]] \\
                  \amp [$left[1]] = [$right[1]]
                  \end{alignedat}
                  \right.
                `]

[@KeyboardInstructions('Write the solution in the format [`[$X] = \text{number}, [$Y] = \text{number}\text{.}`] If there is no solution, enter [|no solutions|]*. If there are infinitely many solutions, enter [|infinitely many solutions|]*.')@]**

[_]{$answer}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
